import{_ as a,o as s,c as n,ai as o}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"Modal & Dialog Systems","description":"The layered modal and dialog overlay system — sections, focus cycling, command palette, confirmation dialogs, and permission prompts.","frontmatter":{"title":"Modal & Dialog Systems","description":"The layered modal and dialog overlay system — sections, focus cycling, command palette, confirmation dialogs, and permission prompts.","outline":[2,3]},"headers":[],"relativePath":"cli/modals.md","filePath":"cli/modals.md","lastUpdated":0}'),l={name:"cli/modals.md"};function i(t,e,r,c,d,p){return s(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="modal-dialog-systems" tabindex="-1">Modal &amp; Dialog Systems <a class="header-anchor" href="#modal-dialog-systems" aria-label="Permalink to “Modal &amp; Dialog Systems”">​</a></h1><h2 id="modal-system" tabindex="-1">Modal System <a class="header-anchor" href="#modal-system" aria-label="Permalink to “Modal System”">​</a></h2><p>Modals are centered overlays with dimmed background. The compositing pipeline works row-by-row: rows within the modal&#39;s Y range use <code>compositeRow()</code> to insert modal content into a dimmed background; rows above/below are fully dimmed.</p><p><strong>Section types available:</strong></p><ul><li><code>TextSection</code> — Static text, word-wrapped</li><li><code>SpacerSection</code> — Blank line</li><li><code>ButtonsSection</code> — Row of buttons (Normal/Primary/Danger variants)</li><li><code>InputSection</code> — Single-line text input</li><li><code>TextareaSection</code> — Multi-line text input</li><li><code>ListSection</code> — Scrollable selection list</li><li><code>CheckboxSection</code> — Toggleable checkbox</li><li><code>WhenSection</code> — Conditional section</li></ul><p><strong>Modal variants:</strong> Default (purple border), Danger (red), Warning (amber), Info (blue)</p><p><strong>Focus cycling:</strong> Tab/Shift+Tab cycles through focusable elements using modular arithmetic.</p><h2 id="command-palette" tabindex="-1">Command Palette <a class="header-anchor" href="#command-palette" aria-label="Permalink to “Command Palette”">​</a></h2><p>Activated with <code>Ctrl+P</code> or <code>:</code>. Provides fuzzy search across all plugin commands.</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>╭────────────────────── Command Palette ──────────────────────╮</span></span>
<span class="line"><span>│  [Search: sp                                               ]│</span></span>
<span class="line"><span>│                                                              │</span></span>
<span class="line"><span>│  &gt; [Spectrum] Focus — Open Spectrum dashboard               │</span></span>
<span class="line"><span>│    [Spectrum] Start — Begin story execution                  │</span></span>
<span class="line"><span>│    [Spectrum] Stop — Stop execution                          │</span></span>
<span class="line"><span>│    [Spectrum] Next Story — Go to next story page             │</span></span>
<span class="line"><span>│    [Spectrum] Switch Epic — Switch to next epic              │</span></span>
<span class="line"><span>│                                                              │</span></span>
<span class="line"><span>│  ↑/↓ navigate • enter execute • esc close                   │</span></span>
<span class="line"><span>╰──────────────────────────────────────────────────────────────╯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="dialog-system" tabindex="-1">Dialog System <a class="header-anchor" href="#dialog-system" aria-label="Permalink to “Dialog System”">​</a></h2><p>Dialogs are layered above modals in z-order. Two dialog types:</p><p><strong>Confirmation Dialog:</strong></p><ul><li>Two buttons: Confirm + Cancel</li><li>Quick keys: <code>y</code> for confirm, <code>n</code> for cancel</li><li>Variant-colored border</li></ul><p><strong>Permission Dialog:</strong></p><ul><li>Three buttons: Allow + Allow Session + Deny</li><li>Scrollable preview area (max 8 lines)</li><li>Quick keys: <code>a</code> for allow, <code>s</code> for allow session, <code>d</code>/<code>n</code> for deny</li><li>Amber border with &quot;Permission Required&quot; title</li></ul>`,16)])])}const b=a(l,[["render",i]]);export{u as __pageData,b as default};
